// LookupEntity resolves an integration entity via GET /api/lookup/{app}/{id}.
//
// Uses the raw (non-WithResponse) generated client to avoid a JSON parse
// error on 422 responses. The backend may return a non-standard 422 body
// ({"detail": "unknown app"} with detail as a string), which would fail
// parsing into HTTPValidationError.Detail (*[]ValidationError). By using
// the raw client we read the status code directly and return sentinel errors.
func (c *HubClient) LookupEntity(ctx context.Context, app, id string) (*LookupResult, error) {
	start := time.Now()
	appParam := LookupApiLookupAppEntityIdGetParamsApp(app)
	rawResp, err := c.gen.LookupApiLookupAppEntityIdGet(ctx, appParam, id)
	logCall("LookupEntity", start, err)
	if err != nil {
		return nil, err
	}
	defer rawResp.Body.Close()
	switch rawResp.StatusCode {
	case http.StatusNotFound:
		return nil, ErrNotFound
	case http.StatusUnprocessableEntity:
		return nil, ErrUnsupportedApp
	case http.StatusOK:
		// fall through to parse the body
	default:
		return nil, fmt.Errorf("LookupEntity: status %d", rawResp.StatusCode)
	}
	var result LookupResult
	if err := json.NewDecoder(rawResp.Body).Decode(&result); err != nil {
		return nil, fmt.Errorf("LookupEntity: decode: %w", err)
	}
	return &result, nil
}

// RenderPreview requests a PNG preview for a template from POST /api/render/preview.
// Returns the raw PNG bytes on success, or an error when the endpoint is unavailable
// or the render fails. Callers should treat any error as "show placeholder" — the
// endpoint is optional and may not yet be implemented by all backend versions.
func (c *HubClient) RenderPreview(ctx context.Context, templateKey string) ([]byte, error) {
	start := time.Now()
	previewURL := c.baseURL + "/api/render/preview?key=" + url.QueryEscape(templateKey)
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, previewURL, nil)
	if err != nil {
		return nil, err
	}
	resp, err := c.hc.Do(req)
	logCall("RenderPreview", start, err)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("RenderPreview: status %d", resp.StatusCode)
	}
	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, err
	}
	return data, nil
}

// CheckHealth performs a GET /healthz against the backend and returns an error if unavailable.
func (c *HubClient) CheckHealth(ctx context.Context) error {
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, c.baseURL+"/healthz", nil)
	if err != nil {
		return err
	}
	resp, err := c.hc.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("backend healthz: %d", resp.StatusCode)
	}
	return nil
}

// parseUUID parses a string into an openapi_types.UUID.
func parseUUID(s string) (openapi_types.UUID, error) {
	var u openapi_types.UUID
	err := u.UnmarshalText([]byte(s))
	return u, err
}
